mapper.select:
SELECT sa.*, u.username AS user_name, u.phone AS user_phone, s.station_name AS station_name, a.username AS auditor_name FROM shipping_appointment sa LEFT JOIN user u ON sa.user_id = u.id LEFT JOIN station s ON sa.station_id = s.id LEFT JOIN user a ON sa.auditor_id = a.id
AND sa.user_id = #{userId}
AND sa.status = #{status}
AND sa.station_id = #{stationId}
ORDER BY sa.create_time DESC
